import React from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Button,
  Chip,
  Tabs,
  Tab,
  CircularProgress
} from '@mui/material';
import {
  Event as EventIcon,
  Person as PersonIcon,
  Euro as EuroIcon,
  CheckCircle as CheckIcon,
  AccessTime as PendingIcon,
  Cancel as CancelIcon
} from '@mui/icons-material';
import { useBookings } from '../context/BookingContext';

const Bookings = () => {
  const { 
    bookings, 
    loading, 
    getActiveBookings, 
    getPastBookings, 
    getIncomingBookings 
  } = useBookings();
  const [activeTab, setActiveTab] = React.useState(0);

  const getStatusChip = (status) => {
    switch (status) {
      case 'active':
        return (
          <Chip 
            icon={<CheckIcon />} 
            label="Active" 
            sx={{ 
              backgroundColor: '#E8F5E9', 
              color: '#2E7D32',
              fontWeight: 600
            }} 
          />
        );
      case 'completed':
        return (
          <Chip 
            icon={<CheckIcon />} 
            label="Completed" 
            sx={{ 
              backgroundColor: '#E0F7F7', 
              color: '#008080',
              fontWeight: 600
            }} 
          />
        );
      case 'pending':
        return (
          <Chip 
            icon={<PendingIcon />} 
            label="Pending" 
            sx={{ 
              backgroundColor: '#FFF8E1', 
              color: '#FF8F00',
              fontWeight: 600
            }} 
          />
        );
      default:
        return null;
    }
  };

  const renderBookingCard = (booking) => (
    <Card sx={{ 
      borderRadius: '16px', 
      boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
      mb: 3
    }}>
      <CardContent>
        <Grid container spacing={2}>
          <Grid item xs={12} sm={4}>
            <CardMedia
              component="img"
              height="150"
              image={booking.image}
              alt={booking.title}
              sx={{ borderRadius: '12px' }}
            />
          </Grid>
          <Grid item xs={12} sm={8}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 1 }}>
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                {booking.title}
              </Typography>
              {getStatusChip(booking.status)}
            </Box>

            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              {booking.description}
            </Typography>

            <Grid container spacing={1} sx={{ mb: 2 }}>
              <Grid item xs={6}>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <EventIcon sx={{ color: '#008080', mr: 1 }} />
                  <Typography variant="body2">
                    {booking.start_date} to {booking.end_date}
                  </Typography>
                </Box>
              </Grid>
              <Grid item xs={6}>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <PersonIcon sx={{ color: '#008080', mr: 1 }} />
                  <Typography variant="body2">
                    Owner: {booking.owner}
                  </Typography>
                </Box>
              </Grid>
              <Grid item xs={6}>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <EuroIcon sx={{ color: '#008080', mr: 1 }} />
                  <Typography variant="body2">
                    Total: €{booking.price}
                  </Typography>
                </Box>
              </Grid>
            </Grid>

            <Box sx={{ display: 'flex', gap: 1 }}>
              {booking.status === 'pending' && (
                <Button 
                  variant="contained" 
                  size="small"
                  sx={{ 
                    backgroundColor: '#008080',
                    color: 'white',
                    borderRadius: '9999px',
                    fontWeight: 600,
                    '&:hover': {
                      backgroundColor: '#006666',
                    }
                  }}
                >
                  Confirm
                </Button>
              )}
              {booking.status === 'active' && (
                <Button 
                  variant="outlined" 
                  size="small"
                  sx={{ 
                    borderColor: '#008080',
                    color: '#008080',
                    borderRadius: '9999px',
                    fontWeight: 600,
                    '&:hover': {
                      backgroundColor: 'rgba(0, 128, 128, 0.1)',
                      borderColor: '#006666',
                    }
                  }}
                >
                  Extend
                </Button>
              )}
              <Button 
                variant="outlined" 
                size="small"
                sx={{ 
                  borderColor: '#5A7D8C',
                  color: '#5A7D8C',
                  borderRadius: '9999px',
                  fontWeight: 600,
                  '&:hover': {
                    backgroundColor: 'rgba(90, 125, 140, 0.1)',
                    borderColor: '#455A64',
                  }
                }}
              >
                Message
              </Button>
            </Box>
          </Grid>
        </Grid>
      </CardContent>
    </Card>
  );

  const activeBookings = getActiveBookings();
  const pastBookings = getPastBookings();
  const incomingBookings = getIncomingBookings();

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'center', 
          alignItems: 'center', 
          height: '60vh' 
        }}>
          <CircularProgress sx={{ color: '#008080' }} />
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          My Bookings
        </Typography>

        <Box sx={{ 
          backgroundColor: 'white', 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          mb: 4
        }}>
          <Tabs 
            value={activeTab} 
            onChange={(e, newValue) => setActiveTab(newValue)}
            sx={{ 
              '& .MuiTabs-indicator': {
                backgroundColor: '#008080',
              }
            }}
          >
            <Tab 
              label={`Active (${activeBookings.length})`} 
              sx={{ 
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                }
              }} 
            />
            <Tab 
              label={`Past (${pastBookings.length})`} 
              sx={{ 
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                }
              }} 
            />
            <Tab 
              label={`Incoming (${incomingBookings.length})`} 
              sx={{ 
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                }
              }} 
            />
          </Tabs>

          <Box sx={{ p: 3 }}>
            {activeTab === 0 && (
              <Box>
                <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                  Active Bookings
                </Typography>
                {activeBookings.length > 0 ? (
                  activeBookings.map(booking => renderBookingCard(booking))
                ) : (
                  <Typography variant="body1" sx={{ textAlign: 'center', py: 4, color: '#5A7D8C' }}>
                    You don't have any active bookings.
                  </Typography>
                )}
              </Box>
            )}

            {activeTab === 1 && (
              <Box>
                <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                  Past Bookings
                </Typography>
                {pastBookings.length > 0 ? (
                  pastBookings.map(booking => renderBookingCard(booking))
                ) : (
                  <Typography variant="body1" sx={{ textAlign: 'center', py: 4, color: '#5A7D8C' }}>
                    You don't have any past bookings.
                  </Typography>
                )}
              </Box>
            )}

            {activeTab === 2 && (
              <Box>
                <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                  Incoming Bookings
                </Typography>
                {incomingBookings.length > 0 ? (
                  incomingBookings.map(booking => renderBookingCard(booking))
                ) : (
                  <Typography variant="body1" sx={{ textAlign: 'center', py: 4, color: '#5A7D8C' }}>
                    You don't have any incoming bookings.
                  </Typography>
                )}
              </Box>
            )}
          </Box>
        </Box>
      </Box>
    </Container>
  );
};

export default Bookings;
